29: 	}
30: 	if dashboard["time"] == nil {
31: 		dashboard["time"] = map[string]interface{}{
32: 			"from": "now-6h",
33: 			"to":   "now",
34: 		}
35: 	}
36: 	if dashboard["timepicker"] == nil {
