195: // sortPanelsByGridPos sorts panels by grid position (y first, then x)
196: func sortPanelsByGridPos(dashboard map[string]interface{}) {
197: 	panels := getPanels(dashboard)
198: 	if len(panels) == 0 {
199: 		return
200: 	}
201: 
202: 	sort.SliceStable(panels, func(i, j int) bool {
203: 		panelA := panels[i]
204: 		panelB := panels[j]
205: 
206: 		gridPosA, okA := panelA["gridPos"].(map[string]interface{})
207: 		gridPosB, okB := panelB["gridPos"].(map[string]interface{})
208: 
209: 		if !okA || !okB {
210: 			return false
211: 		}
212: 
213: 		yA, okA := gridPosA["y"].(float64)
214: 		yB, okB := gridPosB["y"].(float64)
215: 
216: 		if !okA || !okB {
217: 			return false
218: 		}
219: 
220: 		if yA == yB {
221: 			// Same row, sort by x
222: 			xA, okA := gridPosA["x"].(float64)
223: 			xB, okB := gridPosB["x"].(float64)
224: 
225: 			if !okA || !okB {
226: 				return false
227: 			}
228: 
229: 			return xA < xB
230: 		}
231: 
232: 		return yA < yB
233: 	})
234: }
