18: /**
19:  * At 7.0, the `table` panel was swapped from an angular implementation to a react one.
20:  * The models do not match, so this process will delegate to the old implementation when
21:  * a saved table configuration exists.
22:  */
23: export const tableMigrationHandler = (panel: PanelModel<Options>): Partial<Options> => {
24:   // Table was saved as an angular table, lets just swap to the 'table-old' panel
25:   if (!panel.pluginVersion && 'columns' in panel) {
26:     console.log('Was angular table', panel);
27:   }
28: 
29:   migrateTextWrapToFieldLevel(panel);
30:   migrateHiddenFields(panel);
31:   migrateFooterV2(panel);
32: 
33:   // Nothing changed
34:   return panel.options;
35: };
