37: const transformsMap = {
38:   timeseries_to_rows: 'seriesToRows',
39:   timeseries_to_columns: 'seriesToColumns',
40:   timeseries_aggregations: 'reduce',
41:   table: 'merge',
42: };
43: 
44: const columnsMap = {
45:   avg: 'mean',
46:   min: 'min',
47:   max: 'max',
48:   total: 'sum',
49:   current: 'lastNotNull',
50:   count: 'count',
51: };
52: 
53: const colorModeMap = {
54:   cell: 'color-background',
55:   row: 'color-background',
56:   value: 'color-text',
57: };
58: 
59: type Transformations = keyof typeof transformsMap;
60: 
61: type Transformation = {
62:   id: string;
63:   options: ReduceTransformerOptions;
64: };
65: 
66: type Columns = keyof typeof columnsMap;
67: 
68: type Column = {
69:   value: Columns;
70:   text: string;
71: };
72: 
73: type ColorModes = keyof typeof colorModeMap;
74: 
75: const generateThresholds = (thresholds: string[], colors: string[]) => {
76:   return [-Infinity, ...thresholds].map((threshold, idx) => ({
77:     color: colors[idx],
78:     value: isNumber(threshold) ? threshold : parseInt(threshold, 10),
79:   }));
80: };
81: 
82: const migrateTransformations = (
83:   panel: PanelModel<Partial<Options>>,
84:   oldOpts: { columns: any; transform: Transformations }
85: ) => {
86:   const transformations: Transformation[] = panel.transformations ?? [];
87:   if (Object.keys(transformsMap).includes(oldOpts.transform)) {
88:     const opts: ReduceTransformerOptions = {
89:       reducers: [],
90:     };
91:     if (oldOpts.transform === 'timeseries_aggregations') {
92:       opts.includeTimeField = false;
93:       opts.reducers = oldOpts.columns.map((column: Column) => columnsMap[column.value]);
94:     }
95:     transformations.push({
96:       id: transformsMap[oldOpts.transform],
97:       options: opts,
98:     });
99:   }
100:   return transformations;
101: };
102: 
103: type Style = {
104:   unit: string;
105:   type: string;
106:   alias: string;
107:   decimals: number;
108:   colors: string[];
109:   colorMode: ColorModes;
110:   pattern: string;
111:   thresholds: string[];
112:   align?: string;
113:   dateFormat: string;
114:   link: boolean;
115:   linkTargetBlank?: boolean;
116:   linkTooltip?: string;
117:   linkUrl?: string;
118: };
119: 
120: const migrateTableStyleToOverride = (style: Style) => {
121:   const fieldMatcherId = /^\/.*\/$/.test(style.pattern) ? FieldMatcherID.byRegexp : FieldMatcherID.byName;
122:   const override: ConfigOverrideRule = {
123:     matcher: {
124:       id: fieldMatcherId,
125:       options: style.pattern,
126:     },
127:     properties: [],
128:   };
129: 
130:   if (style.alias) {
131:     override.properties.push({
132:       id: 'displayName',
133:       value: style.alias,
134:     });
135:   }
136: 
137:   if (style.unit) {
138:     override.properties.push({
139:       id: 'unit',
140:       value: style.unit,
141:     });
142:   }
143: 
144:   if (style.decimals !== undefined) {
145:     override.properties.push({
146:       id: 'decimals',
147:       value: style.decimals,
148:     });
149:   }
150: 
151:   if (style.type === 'date') {
152:     override.properties.push({
153:       id: 'unit',
154:       value: `time: ${style.dateFormat}`,
155:     });
156:   }
157: 
158:   if (style.type === 'hidden') {
159:     override.properties.push({
160:       id: 'custom.hidden',
161:       value: true,
162:     });
163:   }
164: 
165:   if (style.link) {
166:     override.properties.push({
167:       id: 'links',
168:       value: [
169:         {
170:           title: defaultTo(style.linkTooltip, ''),
171:           url: defaultTo(style.linkUrl, ''),
172:           targetBlank: defaultTo(style.linkTargetBlank, false),
173:         },
174:       ],
175:     });
176:   }
177: 
178:   if (style.colorMode) {
179:     override.properties.push({
180:       id: 'custom.cellOptions',
181:       value: {
182:         type: colorModeMap[style.colorMode],
183:       },
184:     });
185:   }
186: 
187:   if (style.align) {
188:     override.properties.push({
189:       id: 'custom.align',
190:       value: style.align === 'auto' ? null : style.align,
191:     });
192:   }
193: 
194:   if (style.thresholds?.length && style.colors?.length) {
195:     override.properties.push({
196:       id: 'thresholds',
197:       value: {
198:         mode: ThresholdsMode.Absolute,
199:         steps: generateThresholds(style.thresholds, style.colors),
200:       },
201:     });
202:   }
203: 
204:   return override;
205: };
206: 
207: const migrateDefaults = (prevDefaults: Style) => {
208:   let defaults: FieldConfig = {
209:     custom: {},
210:   };
211:   if (prevDefaults) {
212:     defaults = omitBy(
213:       {
214:         unit: prevDefaults.unit,
215:         decimals: prevDefaults.decimals,
216:         displayName: prevDefaults.alias,
217:         custom: {
218:           align: prevDefaults.align === 'auto' ? null : prevDefaults.align,
219:         },
220:       },
221:       isNil
222:     );
223: 
224:     if (prevDefaults.thresholds && prevDefaults.thresholds.length) {
225:       const thresholds: ThresholdsConfig = {
226:         mode: ThresholdsMode.Absolute,
227:         steps: generateThresholds(prevDefaults.thresholds, prevDefaults.colors),
228:       };
229:       defaults.thresholds = thresholds;
230:     }
231: 
232:     if (prevDefaults.colorMode) {
233:       defaults.custom.cellOptions = {
234:         type: colorModeMap[prevDefaults.colorMode],
235:       };
236:     }
237:   }
238:   return defaults;
239: };
