494:   // Let panel plugins inspect options from previous panel and keep any that it can use
495:   private callPanelTypeChangeHandler(
496:     newPlugin: PanelPlugin,
497:     oldPluginId: string,
498:     oldOptions: any,
499:     wasAngular: boolean
500:   ) {
501:     if (newPlugin.onPanelTypeChanged) {
502:       const prevOptions = wasAngular ? { angular: oldOptions } : oldOptions.options;
503:       Object.assign(this.options, newPlugin.onPanelTypeChanged(this, oldPluginId, prevOptions, this.fieldConfig));
504:     }
