507:   changePlugin(newPlugin: PanelPlugin) {
508:     const pluginId = newPlugin.meta.id;
509:     const oldOptions = this.getOptionsToRemember();
510:     const prevFieldConfig = this.fieldConfig;
511:     const oldPluginId = this.type;
512:     const angularId = this.autoMigrateFrom || oldPluginId;
513:     const wasAngular = Boolean(autoMigrateAngular[angularId]);
514:     this.cachedPluginOptions[oldPluginId] = {
515:       properties: oldOptions,
516:       fieldConfig: prevFieldConfig,
517:     };
518: 
519:     this.clearPropertiesBeforePluginChange();
520:     this.restorePanelOptions(pluginId);
521: 
522:     // Potentially modify current options
523:     this.callPanelTypeChangeHandler(newPlugin, oldPluginId, oldOptions, wasAngular);
524: 
525:     // switch
526:     this.type = pluginId;
527:     this.plugin = newPlugin;
528:     this.configRev++;
529: 
530:     this.applyPluginOptionDefaults(newPlugin, true);
